INSERT INTO `matiere_classe` (`id`, `coefficient`, `chargehoraire`, `scorecomplexite`, `nom`, `description`) VALUES
(1, 4, 45, 8, 'Algorithmique Avancée', 'Structures de données avancées, complexité algorithmique, graphes et arbres.'),
(2, 3.5, 40, 7, 'Systèmes d\'Exploitation', 'Processus, threads, mémoire virtuelle, systèmes de fichiers Linux/Windows.'),
(3, 3, 35, 6, 'Réseaux Informatiques', 'Protocoles TCP/IP, routage, sécurité réseau et administration système.'),
(4, 3.5, 40, 7, 'Base de Données', 'Modélisation relationnelle, SQL avancé, NoSQL et optimisation de requêtes.'),
(5, 3, 50, 5, 'Développement Web', 'HTML5, CSS3, JavaScript ES6+, frameworks React et Symfony PHP.'),
(6, 3.5, 35, 9, 'Sécurité Informatique', 'Cryptographie, pentesting, OWASP, normes ISO 27001 et gestion des risques.'),
(7, 3, 30, 6, 'UML & Modélisation', 'Diagrammes de classes, séquences, cas d\'utilisation et architecture MVC.'),
(8, 3.5, 35, 8, 'Design Patterns', 'Patterns GoF, SOLID, DRY, Clean Architecture et refactoring avancé.'),
(9, 3, 30, 7, 'Tests & Qualité Logicielle', 'TDD, BDD, tests unitaires, intégration continue et couverture de code.'),
(10, 3.5, 40, 8, 'DevOps & CI/CD', 'Docker, Kubernetes, Jenkins, GitLab CI et déploiement automatisé.'),
(11, 2.5, 25, 5, 'Gestion de Projet Agile', 'Scrum, Kanban, estimation, sprint planning et rétrospectives.'),
(12, 4, 40, 9, 'Architecture Microservices', 'API REST, gRPC, message brokers RabbitMQ/Kafka et service mesh.'),
(13, 3.5, 35, 7, 'Statistiques & Probabilités', 'Distributions, tests d\'hypothèses, régression et analyse multivariée.'),
(14, 3, 45, 5, 'Python Data Science', 'NumPy, Pandas, Matplotlib, Seaborn et analyse exploratoire de données.'),
(15, 4, 50, 9, 'Machine Learning', 'Algorithmes supervisés/non-supervisés, validation croisée et hyperparamètres.'),
(16, 4, 50, 10, 'Deep Learning', 'Réseaux de neurones, CNN, RNN, transformers et fine-tuning de modèles.'),
(17, 3.5, 40, 9, 'Big Data & Spark', 'Hadoop, Apache Spark, Hive, traitement distribué et pipelines de données.'),
(18, 4, 45, 10, 'NLP & Vision par Ordinateur', 'BERT, GPT, OpenCV, détection d\'objets et traitement d\'images médicales.');
