INSERT INTO `quiz_question` (`id`, `question`, `choice_a`, `choice_b`, `choice_c`, `choice_d`, `correct_choice`, `explanation`, `matiere_id`) VALUES
(1, 'Quelle est la complexité de l\'algorithme de tri rapide (QuickSort) dans le pire cas ?', 'O(n log n)', 'O(n²)', 'O(n)', 'O(log n)', 'B', 'Dans le pire cas (tableau déjà trié), QuickSort effectue O(n²) comparaisons.', 1),
(2, 'Quel algorithme de recherche s\'applique uniquement sur un tableau trié ?', 'Recherche linéaire', 'Recherche binaire', 'Recherche hash', 'Recherche BFS', 'B', 'La recherche binaire nécessite impérativement un tableau trié pour fonctionner.', 1),
(3, 'Quelle structure de données est utilisée pour implémenter un BFS (parcours en largeur) ?', 'Pile (Stack)', 'File (Queue)', 'Arbre binaire', 'Graphe pondéré', 'B', 'Le BFS utilise une file (FIFO) pour explorer les nœuds niveau par niveau.', 1),
(4, 'En Algorithmique Avancée, lequel des éléments suivants est correct ?', 'Aperiam dolorem praesentium nihil illo quis voluptatem.', 'Natus ut laborum cupiditate.', 'Harum neque sequi quidem.', 'Ipsum neque commodi nam quos illum.', 'D', 'Deleniti repellat alias non sapiente aliquam ut aperiam cumque molestiae.', 1),
(5, 'En Algorithmique Avancée, lequel des éléments suivants est correct ?', 'Ea quae quia ea.', 'Omnis quas possimus voluptas nisi quibusdam.', 'Natus in aliquid occaecati.', 'Et ipsum accusamus distinctio qui debitis est.', 'C', 'Illum voluptates tenetur facere et ratione quo placeat.', 1),
(6, 'En Algorithmique Avancée, lequel des éléments suivants est correct ?', 'Dignissimos modi amet ex nihil.', 'Quae distinctio et debitis eius eveniet labore.', 'Vitae sint sed qui nisi qui.', 'Sed eos ut et aut illo veritatis.', 'B', 'Eveniet qui pariatur voluptate atque facilis ipsa quas in fugit tempore.', 1),
(7, 'En Algorithmique Avancée, lequel des éléments suivants est correct ?', 'Tempora blanditiis earum quia velit.', 'Distinctio nihil enim suscipit maxime.', 'Minima ad veritatis voluptatum in.', 'Repellat rerum quia optio omnis eaque.', 'C', 'Animi sed dolor distinctio doloremque neque aut ab non nisi.', 1),
(8, 'En Algorithmique Avancée, lequel des éléments suivants est correct ?', 'Odio quo eos soluta.', 'Eos incidunt eligendi non quos consequatur odit.', 'Ut iste nihil ipsa.', 'Repellendus et labore omnis in consequuntur.', 'A', 'Reprehenderit est impedit non autem voluptatem quasi nulla facere similique.', 1),
(9, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Qui reprehenderit laudantium dolores cumque.', 'Voluptatem iusto expedita et inventore quam velit.', 'Iusto animi in veniam nobis dolorem.', 'Vero reiciendis vitae dolor.', 'C', 'Delectus non dolore quam facilis nihil accusamus exercitationem odit iure maxime minima possimus nihil repellat doloribus.', 2),
(10, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Id consequuntur voluptate voluptates rerum sit.', 'Molestiae deleniti saepe commodi.', 'Ipsam veritatis voluptatem quod quaerat.', 'Consequatur ut est aliquid sit.', 'A', 'Eligendi saepe tenetur qui necessitatibus numquam debitis eveniet molestiae consectetur nisi quod dolore reprehenderit perspiciatis officia.', 2),
(11, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Ex laudantium explicabo molestiae numquam et nisi.', 'Dolores voluptas neque quia iste saepe quia.', 'Et maiores qui voluptate.', 'Error qui animi possimus.', 'A', 'Eveniet ut quasi et aut laborum doloremque velit et ea mollitia hic aut dolorem aut.', 2),
(12, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Saepe assumenda delectus repellat commodi.', 'Et at aut eveniet nemo.', 'Illo quis qui nisi.', 'Debitis beatae commodi distinctio.', 'A', 'Eius recusandae sed soluta reprehenderit voluptatem odit ipsa dignissimos architecto libero id qui fuga quisquam.', 2),
(13, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Unde magni voluptatem est ea facilis.', 'Animi sit doloremque aut porro.', 'Officiis nisi occaecati dicta consectetur et laboriosam.', 'Vel ut aliquid dolore omnis impedit omnis.', 'B', 'Voluptatem veritatis unde nesciunt fugiat dolorem quae ipsum voluptatem voluptas.', 2),
(14, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'A maiores repellendus consequatur sit.', 'Ut ipsa deserunt non dolore veniam.', 'Est earum et magni est optio occaecati.', 'Dolore voluptas est dolor.', 'A', 'Velit nam labore ipsam magnam qui voluptates debitis quaerat velit architecto quo asperiores aut provident tenetur.', 2),
(15, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Reprehenderit laboriosam rerum soluta perspiciatis eveniet sit.', 'Accusantium reprehenderit tenetur necessitatibus maiores.', 'Sint delectus fugit est et.', 'Incidunt nihil beatae nam.', 'C', 'Eum tenetur ea quo ratione dolorem pariatur quidem numquam minus est quisquam sit.', 2),
(16, 'En Systèmes d\'Exploitation, lequel des éléments suivants est correct ?', 'Qui rerum id voluptatibus numquam.', 'Assumenda quis molestiae consectetur itaque.', 'Repudiandae debitis nisi fugiat.', 'Quis sunt atque explicabo maiores et.', 'C', 'Ut omnis nihil sapiente placeat unde consequuntur sunt voluptatibus mollitia culpa nisi nostrum officia quaerat.', 2),
(17, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Ab dicta laboriosam et enim nostrum asperiores.', 'Eius quod voluptas ipsum voluptatibus eum.', 'Veritatis distinctio ipsum porro.', 'Vero sunt recusandae sint sit omnis.', 'A', 'Dolores assumenda sunt quia maiores at optio ea.', 3),
(18, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Vero velit ut nemo dolores cum.', 'Ut autem eaque harum deserunt magnam est placeat.', 'Ipsum perspiciatis totam corporis rerum.', 'Aut aut sapiente ipsam pariatur dolores beatae.', 'C', 'Laudantium perferendis enim rerum quisquam est exercitationem nostrum quo error.', 3),
(19, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Soluta autem quo cupiditate magni velit.', 'Magnam alias similique aut.', 'Animi et facere ut.', 'Magni natus maxime veritatis cumque sunt.', 'C', 'Dolores autem officiis incidunt deleniti pariatur eaque aut ipsa.', 3),
(20, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Necessitatibus quaerat quia nulla molestias ab minus.', 'Et beatae dolorum voluptas sapiente qui.', 'Placeat amet accusantium est.', 'Sit non doloribus dicta quia sit est.', 'A', 'Aperiam id fugit molestias assumenda modi voluptatem omnis.', 3),
(21, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Ut ea et repellat error.', 'Nihil adipisci itaque eaque adipisci.', 'Praesentium et odio numquam sequi ratione occaecati.', 'Ea excepturi fuga repellendus accusantium voluptates.', 'A', 'Totam aut ea et aspernatur omnis est provident nulla sint expedita sed voluptatem.', 3),
(22, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Modi sequi expedita eum tempora non quidem.', 'Ipsum iusto quae libero debitis sapiente.', 'Suscipit sit expedita voluptatem.', 'Sapiente minus ab suscipit magni sint.', 'A', 'Unde quisquam tempora dolorem et et quidem maiores et porro voluptatibus asperiores similique iure.', 3),
(23, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Magni aperiam consequatur impedit occaecati.', 'Accusamus molestias ea voluptas.', 'Alias dolorum adipisci minus.', 'Pariatur ut et magni dolores voluptas amet.', 'C', 'Iste voluptatem voluptatibus architecto ab doloremque harum assumenda.', 3),
(24, 'En Réseaux Informatiques, lequel des éléments suivants est correct ?', 'Iure omnis nam laborum id vel.', 'Commodi deserunt repudiandae quaerat omnis eos dolores.', 'Quis corrupti qui qui.', 'Praesentium repellendus quas tempora ut rerum sed.', 'D', 'Dignissimos rerum quis beatae et exercitationem omnis culpa et quia quasi.', 3),
(25, 'Quel est le rôle de la clause GROUP BY en SQL ?', 'Filtrer les lignes', 'Regrouper les lignes par valeur', 'Trier les résultats', 'Joindre deux tables', 'B', 'GROUP BY regroupe les lignes ayant des valeurs identiques dans des colonnes spécifiées.', 4),
(26, 'Quelle forme normale élimine les dépendances transitives ?', '1NF', '2NF', '3NF', 'BCNF', 'C', 'La 3ème forme normale (3NF) interdit les dépendances transitives entre attributs non-clés.', 4),
(27, 'En Base de Données, lequel des éléments suivants est correct ?', 'Suscipit cumque dicta numquam.', 'Aut ipsa porro a.', 'Ut perspiciatis qui ea quia.', 'Est cumque pariatur dolorum natus rerum ea.', 'B', 'Dolore nostrum consectetur perspiciatis corrupti dolore aut voluptas doloremque ad a ut iusto.', 4),
(28, 'En Base de Données, lequel des éléments suivants est correct ?', 'Reiciendis magnam a atque delectus rem error.', 'Dignissimos aut consequuntur quibusdam atque qui et.', 'Velit amet aut quae placeat.', 'Ut quod ut optio.', 'D', 'Facilis eum nihil rerum quis et mollitia veritatis fugit aut excepturi deleniti beatae magni magnam natus.', 4),
(29, 'En Base de Données, lequel des éléments suivants est correct ?', 'Accusamus voluptates ipsam molestiae.', 'Quas quia consectetur laborum et magnam.', 'Aut molestiae aut consectetur.', 'Eum temporibus nesciunt magni asperiores.', 'D', 'Laborum vero ut ut in sint sed et sed.', 4),
(30, 'En Base de Données, lequel des éléments suivants est correct ?', 'Eligendi sint magni officiis sed itaque qui.', 'Necessitatibus qui mollitia et totam aut.', 'Aliquid dolorem voluptatum molestiae.', 'Numquam consequuntur quos vel facilis nihil.', 'B', 'Rerum omnis ratione facere cumque sed consequatur voluptates minus et illum et.', 4),
(31, 'En Base de Données, lequel des éléments suivants est correct ?', 'Quia est omnis exercitationem quidem.', 'Est cum nostrum exercitationem.', 'Non non numquam quas.', 'Provident est quas tenetur.', 'D', 'Eos quos tempore et delectus perferendis voluptatem a a earum voluptatem.', 4),
(32, 'En Base de Données, lequel des éléments suivants est correct ?', 'Cupiditate a quos qui molestiae aliquid voluptatum.', 'Voluptatum dicta magni adipisci laboriosam ad.', 'Necessitatibus veritatis nam qui distinctio ex.', 'Suscipit est iusto quia distinctio sunt.', 'A', 'Mollitia itaque consequatur rem voluptas cumque asperiores dolores.', 4),
(33, 'En Développement Web, lequel des éléments suivants est correct ?', 'Tenetur cumque est aut facilis enim.', 'Aspernatur repudiandae deserunt non.', 'Quidem ut molestiae aut qui magni.', 'Quidem natus ut quod laborum voluptate.', 'A', 'Enim dolorem beatae et omnis ut nulla quo qui corporis voluptatibus voluptates.', 5),
(34, 'En Développement Web, lequel des éléments suivants est correct ?', 'Quasi fuga ex modi qui laborum.', 'Omnis voluptas non temporibus sint.', 'Ab minus illum molestiae aut et.', 'Quia quisquam in voluptate amet.', 'B', 'Aliquid praesentium cum deserunt recusandae maiores hic et sit voluptas similique officiis rerum iusto vel laborum.', 5),
(35, 'En Développement Web, lequel des éléments suivants est correct ?', 'Officia facilis facere eos.', 'Dicta iusto in natus voluptates qui consequatur.', 'Eum velit iusto neque qui.', 'Et dolore sapiente modi voluptas amet nulla.', 'C', 'Repellendus blanditiis qui non omnis ullam culpa id culpa corrupti quos iure est et commodi laboriosam est.', 5),
(36, 'En Développement Web, lequel des éléments suivants est correct ?', 'Pariatur accusantium error omnis repudiandae eveniet accusantium.', 'Enim aut et nemo tempora ducimus.', 'Voluptates expedita harum non.', 'Et libero possimus velit velit vel.', 'B', 'Deleniti voluptate dignissimos qui aut et illum fuga nulla est.', 5),
(37, 'En Développement Web, lequel des éléments suivants est correct ?', 'Et necessitatibus vel voluptatem aperiam porro totam.', 'Officia voluptatem voluptate tenetur rerum quia.', 'Quia quibusdam consequatur fuga aut.', 'Quam quae et enim sunt eaque.', 'C', 'Quo perspiciatis sit eveniet quisquam esse qui velit quis quam voluptatibus quod delectus.', 5),
(38, 'En Développement Web, lequel des éléments suivants est correct ?', 'Enim sunt mollitia cumque.', 'Corrupti non nisi aliquam reiciendis.', 'Maxime beatae et dolorem ipsam cum enim.', 'Asperiores quas quaerat laboriosam magni temporibus.', 'B', 'Ut autem illo dolores est nam aut non.', 5),
(39, 'En Développement Web, lequel des éléments suivants est correct ?', 'Neque necessitatibus voluptatem tempore harum.', 'Esse perspiciatis molestias eum vel iste animi.', 'Distinctio numquam maiores laudantium culpa corrupti expedita.', 'Molestias laborum quia ullam a sit.', 'C', 'Dolor quod eligendi dolor et earum delectus a aut unde rerum.', 5),
(40, 'En Développement Web, lequel des éléments suivants est correct ?', 'Molestias cum enim aut veritatis.', 'Nam at aut ipsam unde.', 'Consequatur sit dolores quia ipsam blanditiis quia.', 'Molestiae autem nostrum aut.', 'A', 'Libero ducimus nam non et voluptates est cupiditate sint deserunt.', 5),
(41, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Consequatur incidunt officiis et.', 'Maxime modi eos aut quia est iusto.', 'Natus dolore ratione eum non molestias non.', 'Voluptatem in odio rem quia facilis quia.', 'B', 'Consequatur eaque non velit nesciunt neque nisi magni omnis repudiandae est repudiandae maiores laboriosam vel voluptates.', 6),
(42, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Est excepturi velit ea qui nobis dignissimos.', 'Repellendus consequatur nam labore dolorem voluptas quia.', 'Omnis in praesentium quis voluptas eum.', 'Molestiae illo ut qui reprehenderit.', 'C', 'Et repellat nisi est autem a qui veritatis aspernatur explicabo.', 6),
(43, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Voluptatem numquam facilis qui voluptas animi ab.', 'Itaque impedit ut et autem nesciunt reprehenderit.', 'Sit deleniti tenetur ducimus rerum molestias sed voluptatem.', 'Dolorem deserunt ea temporibus.', 'A', 'Placeat dicta et illum ratione eaque ut nemo quisquam.', 6),
(44, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Accusantium ad voluptatem maxime dolores aut veniam.', 'Dignissimos quod et animi aspernatur.', 'Accusamus optio enim non.', 'Reiciendis consequatur dolor mollitia.', 'B', 'Quidem enim et voluptatem quasi assumenda porro nesciunt enim eum quia inventore nobis voluptatum et error sit.', 6),
(45, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Voluptatem consequuntur optio eligendi.', 'Dolorum amet earum mollitia minus id vel.', 'Illum vitae doloremque repudiandae et.', 'Consequatur mollitia accusamus quia eius.', 'A', 'Possimus nisi et debitis ipsa fugiat quia aut laboriosam consequatur autem temporibus voluptatem quas sit dolore.', 6),
(46, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Quos non repellat maiores.', 'Ut sapiente quo sunt nulla velit.', 'Exercitationem officiis quia quam adipisci.', 'Aliquam est et animi similique iusto animi.', 'D', 'Nihil iste voluptatibus ut non fugit odit aut et.', 6),
(47, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Quas atque provident rerum.', 'Adipisci ab qui quam architecto qui.', 'Magni laborum quia iusto.', 'Sunt facere aut qui debitis.', 'A', 'Ad accusantium et voluptatum soluta officia velit vero accusantium placeat quibusdam vel aut iusto dolor.', 6),
(48, 'En Sécurité Informatique, lequel des éléments suivants est correct ?', 'Sint incidunt voluptas fugit aut aut.', 'Qui alias ipsum consequatur enim voluptate voluptates.', 'Rem magnam asperiores architecto sed asperiores quia.', 'Labore vitae rerum molestias esse est.', 'B', 'Recusandae dolor laborum maxime placeat consequatur ex eaque sunt non tempora maxime veniam est unde.', 6),
(49, 'En UML & Modélisation, lequel des éléments suivants est correct ?', 'Temporibus est earum dolorem et.', 'Aut provident quos molestiae autem velit.', 'Consectetur ea voluptatem est exercitationem.', 'Est velit eveniet ipsam.', 'B', 'Eius ipsam ut omnis ut sequi facilis consequatur provident sit omnis eaque sequi dolorum eligendi perspiciatis.', 7),
(50, 'En UML & Modélisation, lequel des éléments suivants est correct ?', 'Adipisci quo voluptates minima ut.', 'Sed vitae nobis voluptatem.', 'Cum porro quidem recusandae ducimus.', 'Et sed ut velit est.', 'D', 'Rem eligendi consequatur quae nemo quas minus ratione odit.', 7),
